allow:
Bash(powershell -NoProfile -NonInteractive -ExecutionPolicy Bypass -File - <<'PSEOF'
try {
  $cs = Get-Content 'electron\\loopback-helper.cs' -Raw -Encoding UTF8
  Add-Type -TypeDefinition $cs
  $result = [NetworkIsolationHelper]::EnumAppContainers\(\)
  Write-Output "SUCCESS: length=$\($result.Length\)"
  Write-Output $result.Substring\(0, [Math]::Min\(300, $result.Length\)\)
} catch {
  Write-Output "ERROR: $\($_.Exception.Message\)"
}
PSEOF)
